import React, { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
//slider
import Slider from "react-slick";
import SpecialityService from "../../../services/speciality.service";

const settings = {
  dots: false,
  autoplay: true,
  infinite: true,
  variableWidth: true,
  prevArrow: false,
  nextArrow: false,
  arrows: false,
  initialSlide: 0,
  centerPadding: "500px",
  responsive: [
    {
      breakpoint: 1024,
      settings: {
        slidesToShow: 1,
        slidesToScroll: 1,
      },
    },
    {
      breakpoint: 600,
      settings: {
        slidesToShow: 1,
        slidesToScroll: 1,
      },
    },
    {
      breakpoint: 480,
      settings: {
        slidesToShow: 1,
        slidesToScroll: 1,
      },
    },
  ],
};
const HomeClinic = () => {
  const [t, i18n] = useTranslation();
  const [specilitiesData, setSpecilitiesData] = useState([]);

  useEffect(async () => {
    const specialityResponse = await SpecialityService.getSpecialities();
    // const specialityResponse2 = await APIRequest({
    //   url: specialityUrl,
    //   queryParams: {},
    //   method: "get",
    // });

    console.log(
      `HomeClinic :: specialityResponse: ${JSON.stringify(specialityResponse)}`
    );
    setSpecilitiesData(specialityResponse.body);
  }, []);

  let specilitiesDataList =
    specilitiesData && specilitiesData[0] ? (
      specilitiesData
        .filter((item) => item.isActive)
        .map((speciality, i) => (
          <div key={i}>
            <div className="speicality-item text-center">
              <div className="speicality-img">
                <img
                  src={speciality.image}
                  className="img-fluid"
                  alt="Speciality"
                />
                <span>
                  <i className="fa fa-circle" aria-hidden="true"></i>
                </span>
              </div>
              <p>{speciality.name}</p>
            </div>
          </div>
        ))
    ) : (
      <></>
    );
  return (
    <>
      <section className="section section-specialities">
        <div className="container-fluid">
          <div className="section-header text-center">
            <h2>{t("Specialities")}</h2>
            <p className="sub-title">
              Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do
              eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </p>
          </div>
          <div className="row justify-content-center">
            <div className="col-md-6">
              <div className="specialities-slider slider">
                <Slider {...settings}>{specilitiesDataList}</Slider>
              </div>
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default HomeClinic;
