import React from "react";
import Slider from "react-slick";
import { IMG01, IMG02, IMG03, IMG04, IMG05 } from "./img";

function HomeBanners() {
  const settings = {
    dots: true,
    fade: true,
    infinite: true,
    speed: 1000,
    slidesToShow: 1,
    slidesToScroll: 1,
    arrows: true,
    lazyLoad: true,
  };
  return (
    <div className="section-header text-center">
      <Slider {...settings}>
        <div className="banners-container">
          <img src={IMG01} alt="" />
        </div>
        <div className="banners-container">
          <img src={IMG02} alt="" />
        </div>
        <div className="banners-container">
          <img src={IMG03} alt="" />
        </div>
        <div className="banners-container">
          <img src={IMG04} alt="" />
        </div>
        <div className="banners-container">
          <img src={IMG05} alt="" />
        </div>
      </Slider>
    </div>
  );
}

export default HomeBanners;
